import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"
import "./stepper.css"

const stepperVariants = cva(
  "stepper-base inline-flex items-center",
  {
    variants: {
      size: {
        sm: "gap-[var(--layout-gap-xs)]",
        md: "gap-[var(--layout-gap-sm)]",
      },
    },
    defaultVariants: {
      size: "md",
    },
  }
)

function Stepper({
  className,
  size = "md",
  current = 0,
  total,
  onStepClick,
  ...props
}: Omit<React.ComponentProps<"div">, "children"> &
  VariantProps<typeof stepperVariants> & {
    current?: number
    total: number
    onStepClick?: (step: number) => void
  }) {
  const safeTotal = Math.max(1, total)
  const safeCurrent = Math.max(0, Math.min(current, safeTotal - 1))

  return (
    <div
      data-slot="stepper"
      role="group"
      aria-label={`Step ${safeCurrent + 1} of ${safeTotal}`}
      className={cn(
        stepperVariants({ size, className }),
        size === "sm" ? "stepper-sm" : "stepper-md"
      )}
      {...props}
    >
      {Array.from({ length: safeTotal }, (_, i) => {
        const state =
          i < safeCurrent
            ? "complete"
            : i === safeCurrent
              ? "active"
              : "incomplete"

        const stateClass =
          state === "complete"
            ? "step-dot-complete"
            : state === "active"
              ? "step-dot-active"
              : "step-dot-incomplete"

        const shared = cn("step-dot rounded-full shrink-0", stateClass)

        if (onStepClick) {
          return (
            <button
              key={i}
              data-slot="step-dot"
              type="button"
              className={cn(shared, "step-dot-clickable")}
              aria-label={`Step ${i + 1}`}
              aria-current={state === "active" ? "step" : undefined}
              onClick={() => onStepClick(i)}
            />
          )
        }

        return (
          <span
            key={i}
            data-slot="step-dot"
            className={shared}
            aria-current={state === "active" ? "step" : undefined}
          />
        )
      })}
    </div>
  )
}

export { Stepper, stepperVariants }

/* ================================================================
 * STEPPER — Dot-based Step Indicator
 * Structure (flex, gap) lives in stepper.tsx via cva.
 * Theming (colors, sizes, transitions) lives here via tokens.
 * ================================================================ */

/* --------------------------------
 * Size — custom properties per size
 * -------------------------------- */
.stepper-sm {
  --stepper-dot: 6px;
  --stepper-pill: 18px;
}

.stepper-md {
  --stepper-dot: 8px;
  --stepper-pill: 24px;
}

/* --------------------------------
 * Dot — base dimensions
 * -------------------------------- */
.step-dot {
  height: var(--stepper-dot);
  width: var(--stepper-dot);
}

/* --------------------------------
 * Dot — active pill override
 * -------------------------------- */
.step-dot-active {
  width: var(--stepper-pill);
}

/* --------------------------------
 * Transition — width
 * -------------------------------- */
@media (prefers-reduced-motion: no-preference) {
  .step-dot {
    transition: width 300ms ease, background-color 300ms ease;
  }
}

@media (prefers-reduced-motion: reduce) {
  .step-dot {
    transition: width 800ms ease, background-color 800ms ease;
  }
}

/* --------------------------------
 * State colors
 * -------------------------------- */
.step-dot-complete {
  background-color: var(--text-base-moderate);
}

.step-dot-active {
  background-color: var(--text-base-strong);
}

.step-dot-incomplete {
  background-color: var(--background-neutral-medium-default);
}

/* --------------------------------
 * Clickable — hover & focus
 * -------------------------------- */
.step-dot-clickable {
  cursor: pointer;
  border: none;
  padding: 0;
}

.step-dot-clickable:hover {
  opacity: 0.7;
}

.step-dot-clickable:focus-visible {
  outline: none;
  box-shadow: 0 0 0 2px var(--background-base), 0 0 0 4px var(--border-selected);
}
